import pytest
import cookielib
from unittest.mock import Mock

# Assuming the function is part of a class named PreparedRequest
class TestPreparedRequest:
    @pytest.fixture
    def prepared_request(self):
        return PreparedRequest()

    def test_prepare_cookies_with_cookiejar(self, prepared_request):
        cookie_jar = cookielib.CookieJar()
        prepared_request.prepare_cookies(cookie_jar)
        assert prepared_request._cookies == cookie_jar

    def test_prepare_cookies_with_dict(self, prepared_request):
        cookies_dict = {'session_id': 'abc123', 'user_id': 'user1'}
        prepared_request.prepare_cookies(cookies_dict)
        assert isinstance(prepared_request._cookies, cookielib.CookieJar)

    def test_prepare_cookies_sets_cookie_header(self, prepared_request):
        cookies_dict = {'session_id': 'abc123'}
        prepared_request.prepare_cookies(cookies_dict)
        assert "Cookie" in prepared_request.headers
        assert prepared_request.headers["Cookie"] == "session_id=abc123"

    def test_prepare_cookies_does_not_overwrite_header(self, prepared_request):
        cookies_dict = {'session_id': 'abc123'}
        prepared_request.headers["Cookie"] = "existing_cookie=value"
        prepared_request.prepare_cookies(cookies_dict)
        assert prepared_request.headers["Cookie"] == "existing_cookie=value"

    def test_prepare_cookies_with_empty_dict(self, prepared_request):
        cookies_dict = {}
        prepared_request.prepare_cookies(cookies_dict)
        assert "Cookie" not in prepared_request.headers

    def test_prepare_cookies_with_none(self, prepared_request):
        with pytest.raises(TypeError):
            prepared_request.prepare_cookies(None)

    def test_prepare_cookies_with_invalid_type(self, prepared_request):
        with pytest.raises(TypeError):
            prepared_request.prepare_cookies(123)

    def test_prepare_cookies_called_twice(self, prepared_request):
        cookies_dict = {'session_id': 'abc123'}
        prepared_request.prepare_cookies(cookies_dict)
        prepared_request.prepare_cookies(cookies_dict)  # Call again
        assert prepared_request.headers["Cookie"] == "session_id=abc123"

    def test_prepare_cookies_removes_cookie_header(self, prepared_request):
        cookies_dict = {'session_id': 'abc123'}
        prepared_request.prepare_cookies(cookies_dict)
        prepared_request.headers.pop("Cookie")
        prepared_request.prepare_cookies(cookies_dict)
        assert prepared_request.headers["Cookie"] == "session_id=abc123"

