import pytest

class TestPrepareContentLength:
    @pytest.fixture
    def mock_request(self):
        class MockRequest:
            def __init__(self, method):
                self.method = method
                self.headers = {}

            def prepare_content_length(self, body):
                if body is not None:
                    length = super_len(body)
                    if length:
                        self.headers["Content-Length"] = builtin_str(length)
                elif (
                    self.method not in ("GET", "HEAD")
                    and self.headers.get("Content-Length") is None
                ):
                    self.headers["Content-Length"] = "0"

        return MockRequest

    def test_prepare_content_length_with_body(self, mock_request):
        request = mock_request("POST")
        body = "test body"
        request.prepare_content_length(body)
        assert request.headers["Content-Length"] == "9"

    def test_prepare_content_length_with_empty_body(self, mock_request):
        request = mock_request("POST")
        body = ""
        request.prepare_content_length(body)
        assert request.headers["Content-Length"] == "0"

    def test_prepare_content_length_with_none_body(self, mock_request):
        request = mock_request("POST")
        request.prepare_content_length(None)
        assert request.headers["Content-Length"] == "0"

    def test_prepare_content_length_with_get_method(self, mock_request):
        request = mock_request("GET")
        request.prepare_content_length(None)
        assert "Content-Length" not in request.headers

    def test_prepare_content_length_with_head_method(self, mock_request):
        request = mock_request("HEAD")
        request.prepare_content_length(None)
        assert "Content-Length" not in request.headers

    def test_prepare_content_length_with_no_body_and_no_content_length(self, mock_request):
        request = mock_request("PUT")
        request.prepare_content_length(None)
        assert request.headers["Content-Length"] == "0"

    def test_prepare_content_length_with_no_body_and_content_length_set(self, mock_request):
        request = mock_request("PUT")
        request.headers["Content-Length"] = "100"
        request.prepare_content_length(None)
        assert request.headers["Content-Length"] == "100"

    def test_prepare_content_length_with_large_body(self, mock_request):
        request = mock_request("POST")
        body = "a" * 10000  # Large body
        request.prepare_content_length(body)
        assert request.headers["Content-Length"] == "10000"

    def test_prepare_content_length_with_non_string_body(self, mock_request):
        request = mock_request("POST")
        body = b"binary data"
        request.prepare_content_length(body)
        assert request.headers["Content-Length"] == "12"

