import pytest

class InvalidHeader(Exception):
    pass

_HEADER_VALIDATORS_STR = [re.compile(r'^[^ \t\r\n:]+$'), re.compile(r'^[^ \t\r\n]*$')]
_HEADER_VALIDATORS_BYTE = [re.compile(rb'^[^ \t\r\n:]+$'), re.compile(rb'^[^ \t\r\n]*$')]

def test_validate_header_part_valid_string_name():
    _validate_header_part("Test-Header", "Valid-Header-Name", 0)

def test_validate_header_part_valid_string_value():
    _validate_header_part("Test-Header", "Valid-Header-Value", 1)

def test_validate_header_part_valid_bytes_name():
    _validate_header_part("Test-Header", b'Valid-Header-Name', 0)

def test_validate_header_part_valid_bytes_value():
    _validate_header_part("Test-Header", b'Valid-Header-Value', 1)

def test_validate_header_part_invalid_string_name():
    with pytest.raises(InvalidHeader, match="Invalid leading whitespace, reserved character"):
        _validate_header_part("Test-Header", "Invalid Header Name", 0)

def test_validate_header_part_invalid_string_value():
    with pytest.raises(InvalidHeader, match="Invalid leading whitespace, reserved character"):
        _validate_header_part("Test-Header", "Invalid:Header:Value", 1)

