    response = MockResponse(b'{"key": "value"', '{"key": "value"'}
    with pytest.raises(RequestsJSONDecodeError):
        response.json()

def test_json_unicode_decode_error():
    response = MockResponse(b'\xff\xfe{"key": "value"}', '{"key": "value"}')
    with pytest.raises(RequestsJSONDecodeError):
