        }

        def _format_timeframe(self, timeframe, delta):
            abs_delta = abs(delta)
            form = self.timeframes[timeframe]

            if isinstance(form, str):
                return form.format(abs_delta)

            if delta > 0:
                key = "future"
            else:
                key = "past"
            form = form[key]

            return form.format(abs_delta)

    def setup_method(self):
        self.mock_instance = self.MockClass()

    def test_format_timeframe_future_days(self):
        result = self.mock_instance._format_timeframe('days', 5)
