    class MockClass:
        timeframes = {
            'days': {
                'past': 'በ{} ቀን በፊት',
                'future': 'በ{} ቀን በኋላ'
            },
            'hours': 'በ{} ሰዓት',
            'minutes': {
                'past': 'በ{} ደቂቀ ሰዓት በፊት',
