class TestUtcFromTimestamp:

    @pytest.mark.parametrize("timestamp, expected", [
        (1609459200, Arrow(2021, 1, 1, 0, 0, 0, 0, tzinfo='UTC')),  # Normal case
        (0, Arrow(1970, 1, 1, 0, 0, 0, 0, tzinfo='UTC')),  # Epoch time
        (1633046400.0, Arrow(2021, 10, 1, 0, 0, 0, 0, tzinfo='UTC')),  # Float timestamp
        ("1609459200", Arrow(2021, 1, 1, 0, 0, 0, 0, tzinfo='UTC')),  # String timestamp
        ("0", Arrow(1970, 1, 1, 0, 0, 0, 0, tzinfo='UTC')),  # String epoch time
    ])
    def test_valid_timestamps(self, timestamp, expected):
        result = utcfromtimestamp(Arrow, timestamp)
        assert result == expected

    @pytest.mark.parametrize("timestamp", [
        "invalid",  # Invalid string
        None,       # None value
        {},         # Empty dictionary
        [],         # Empty list
        object(),   # Random object
        -1,         # Negative timestamp
    ])
    def test_invalid_timestamps(self, timestamp):
        with pytest.raises(ValueError) as excinfo:
            utcfromtimestamp(Arrow, timestamp)
        assert f"The provided timestamp {timestamp!r} is invalid." in str(excinfo.value)

    @pytest.mark.parametrize("timestamp", [
        float('nan'),  # NaN
        float('inf'),  # Infinity
        float('-inf'), # Negative Infinity
    ])
    def test_edge_case_timestamps(self, timestamp):
        with pytest.raises(ValueError) as excinfo:
            utcfromtimestamp(Arrow, timestamp)
        assert f"The provided timestamp {timestamp!r} is invalid." in str(excinfo.value)

