def test_parse_multiformat_edge_cases(parser):
    assert parser._parse_multiformat("2023-10-01T14:30:00", ["%Y-%m-%dT%H:%M:%S", "%Y-%m-%d"]) == datetime(2023, 10, 1, 14, 30)
    assert parser._parse_multiformat("2023-10-01 00:00", ["%Y-%m-%d %H:%M", "%Y-%m-%d"]) == datetime(2023, 10, 1)

def test_parse_multiformat_no_matching_format(parser):
    with pytest.raises(ParserError) as excinfo:
