# Assuming the class containing the _get_frames method is named TimeFrame
class TimeFrame:
    _ATTRS = {"year", "month", "day", "hour", "minute", "second", "microsecond"}

    @classmethod
    def _get_frames(cls, name: str) -> Tuple[str, str, int]:
        if name in cls._ATTRS:
            return name, f"{name}s", 1
        elif name[-1] == "s" and name[:-1] in cls._ATTRS:
            return name[:-1], name, 1
        elif name in ["week", "weeks"]:
            return "week", "weeks", 1
        elif name in ["quarter", "quarters"]:
            return "quarter", "months", 3
        else:
            supported = ", ".join(
                [
                    "year(s)",
                    "month(s)",
                    "day(s)",
                    "hour(s)",
                    "minute(s)",
                    "second(s)",
                    "microsecond(s)",
                    "week(s)",
                    "quarter(s)",
                ]
            )
            raise ValueError(
                f"Range or span over frame {name} not supported. Supported frames: {supported}."
            )

def test_get_frames_year():
    assert TimeFrame._get_frames("year") == ("year", "years", 1)

def test_get_frames_month():
    assert TimeFrame._get_frames("month") == ("month", "months", 1)

def test_get_frames_day():
    assert TimeFrame._get_frames("day") == ("day", "days", 1)

def test_get_frames_hour():
    assert TimeFrame._get_frames("hour") == ("hour", "hours", 1)

def test_get_frames_minute():
    assert TimeFrame._get_frames("minute") == ("minute", "minutes", 1)

def test_get_frames_second():
    assert TimeFrame._get_frames("second") == ("second", "seconds", 1)

def test_get_frames_microsecond():
    assert TimeFrame._get_frames("microsecond") == ("microsecond", "microseconds", 1)

def test_get_frames_plural_year():
    assert TimeFrame._get_frames("years") == ("year", "years", 1)

def test_get_frames_plural_month():
    assert TimeFrame._get_frames("months") == ("month", "months", 1)

def test_get_frames_plural_day():
    assert TimeFrame._get_frames("days") == ("day", "days", 1)

def test_get_frames_plural_hour():
    assert TimeFrame._get_frames("hours") == ("hour", "hours", 1)

def test_get_frames_plural_minute():
    assert TimeFrame._get_frames("minutes") == ("minute", "minutes", 1)

def test_get_frames_plural_second():
    assert TimeFrame._get_frames("seconds") == ("second", "seconds", 1)

def test_get_frames_week():
    assert TimeFrame._get_frames("week") == ("week", "weeks", 1)

def test_get_frames_plural_week():
    assert TimeFrame._get_frames("weeks") == ("week", "weeks", 1)

def test_get_frames_quarter():
    assert TimeFrame._get_frames("quarter") == ("quarter", "months", 3)

def test_get_frames_plural_quarter():
    assert TimeFrame._get_frames("quarters") == ("quarter", "months", 3)

def test_get_frames_invalid():
    with pytest.raises(ValueError, match="Range or span over frame invalid_frame not supported"):
        TimeFrame._get_frames("invalid_frame")

def test_get_frames_invalid_plural():
    with pytest.raises(ValueError, match="Range or span over frame invalid_frames not supported"):
        TimeFrame._get_frames("invalid_frames")
