    with pytest.raises(ValueError, match="not recognized as a timezone."):
        _get_tzinfo("Invalid/Timezone")

def test_get_tzinfo_empty_string():
    with pytest.raises(ValueError, match="not recognized as a timezone."):
        _get_tzinfo("")

def test_get_tzinfo_numeric_timezone():
    with pytest.raises(ValueError, match="not recognized as a timezone."):
        _get_tzinfo(123)

def test_get_tzinfo_list_timezone():
    with pytest.raises(ValueError, match="not recognized as a timezone."):
        _get_tzinfo(["America/New_York"])

def test_get_tzinfo_dict_timezone():
