        _get_tzinfo({"timezone": "America/New_York"})

def test_get_tzinfo_tzinfo_subclass():
    class CustomTZ(tz.tzinfo):
        def utcoffset(self, dt):
            return timezone.utc.utcoffset(dt)

        def dst(self, dt):
            return timezone.utc.dst(dt)

        def tzname(self, dt):
            return "CustomTZ"

    custom_tz = CustomTZ()
    assert _get_tzinfo(custom_tz) == custom_tz

