        tzinfo = parse(TestParse, "local")
        assert tzinfo is not None
        assert isinstance(tzinfo, timezone)

    def test_parse_utc(self):
        tzinfo = parse(TestParse, "utc")
        assert tzinfo == timezone.utc

    def test_parse_UTC(self):
        tzinfo = parse(TestParse, "UTC")
        assert tzinfo == timezone.utc

    def test_parse_Z(self):
        tzinfo = parse(TestParse, "Z")
        assert tzinfo == timezone.utc

    def test_parse_positive_offset(self):
        tzinfo = parse(TestParse, "+05:30")
        assert tzinfo.utcoffset(datetime.now()) == timedelta(hours=5, minutes=30)

    def test_parse_negative_offset(self):
        tzinfo = parse(TestParse, "-02:00")
        assert tzinfo.utcoffset(datetime.now()) == timedelta(hours=-2)

    def test_parse_offset_without_minutes(self):
        tzinfo = parse(TestParse, "+05")
        assert tzinfo.utcoffset(datetime.now()) == timedelta(hours=5)

    def test_parse_invalid_offset(self):
        with pytest.raises(ParserError):
            parse(TestParse, "+99:99")

    def test_parse_invalid_timezone_string(self):
        with pytest.raises(ParserError):
            parse(TestParse, "Invalid/Timezone")

    def test_parse_valid_zoneinfo(self):
        tzinfo = parse(TestParse, "America/New_York")
        assert isinstance(tzinfo, ZoneInfo)

    def test_parse_invalid_zoneinfo(self):
        with pytest.raises(ParserError):
            parse(TestParse, "Invalid/Zone")

    def test_parse_empty_string(self):
        with pytest.raises(ParserError):
            parse(TestParse, "")

    def test_parse_none(self):
        with pytest.raises(ParserError):
            parse(TestParse, None)

    def test_parse_invalid_format(self):
        with pytest.raises(ParserError):
            parse(TestParse, "not-a-timezone")

