import pytest

_marker = object()

def first(iterable, default=_marker):
    for item in iterable:
        return item
    if default is _marker:
        raise ValueError(
            'first() was called on an empty iterable, '
            'and no default value was provided.'
        )
    return default

def test_first_with_non_empty_list():
    assert first([0, 1, 2, 3]) == 0
    assert first(['a', 'b', 'c']) == 'a'
    assert first([None, 1, 2]) == None

def test_first_with_empty_list_and_default():
    assert first([], 'some default') == 'some default'
    assert first([], 42) == 42
    assert first([], '') == ''

def test_first_with_empty_list_and_no_default():
    with pytest.raises(ValueError, match='first() was called on an empty iterable'):
        first([])

def test_first_with_single_element_iterable():
    assert first([42]) == 42
    assert first(['only']) == 'only'
    assert first([None]) == None

def test_first_with_generator():
    gen = (x for x in range(5))
    assert first(gen) == 0

def test_first_with_empty_generator_and_default():
    gen_empty = (x for x in [])
    assert first(gen_empty, 'default value') == 'default value'

def test_first_with_empty_generator_and_no_default():
    gen_empty = (x for x in [])
    with pytest.raises(ValueError, match='first() was called on an empty iterable'):
        first(gen_empty)

def test_first_with_tuple():
    assert first((1, 2, 3)) == 1
    assert first((), 'default') == 'default'

def test_first_with_set():
    assert first({1, 2, 3}) in {1, 2, 3}

def test_first_with_dict():
    assert first({'a': 1, 'b': 2}) == 'a'
    assert first({}, 'default') == 'default'

