import pytest

class TestPeek:
    class MockIterator:
        def __init__(self, items):
            self.items = items
            self.index = 0

        def __iter__(self):
            return self

        def __next__(self):
            if self.index < len(self.items):
                item = self.items[self.index]
                self.index += 1
                return item
            raise StopIteration

    class Peekable:
        _marker = object()

        def __init__(self, iterable):
            self._it = iter(iterable)
            self._cache = []

        def peek(self, default=_marker):
            if not self._cache:
                try:
                    self._cache.append(next(self._it))
                except StopIteration:
                    if default is self._marker:
                        raise
                    return default
            return self._cache[0]

    def test_peek_next_item(self):
        peekable = self.Peekable([1, 2, 3])
        assert peekable.peek() == 1

    def test_peek_multiple_calls(self):
        peekable = self.Peekable([1, 2, 3])
        assert peekable.peek() == 1
        assert peekable.peek() == 1

    def test_peek_after_next(self):
        peekable = self.Peekable([1, 2, 3])
        assert peekable.peek() == 1
        next(peekable._it)
        assert peekable.peek() == 2

    def test_peek_empty_iterator_with_default(self):
        peekable = self.Peekable([])
        assert peekable.peek(default='default_value') == 'default_value'

    def test_peek_empty_iterator_without_default(self):
        peekable = self.Peekable([])
        with pytest.raises(StopIteration):
            peekable.peek()

    def test_peek_after_exhaustion(self):
        peekable = self.Peekable([1])
        assert peekable.peek() == 1
        next(peekable._it)
        assert peekable.peek(default='default_value') == 'default_value'

    def test_peek_with_multiple_exhaustions(self):
        peekable = self.Peekable([1, 2])
        assert peekable.peek() == 1
        next(peekable._it)
        assert peekable.peek() == 2
        next(peekable._it)
        assert peekable.peek(default='default_value') == 'default_value'

    def test_peek_with_custom_marker(self):
        custom_marker = object()
        peekable = self.Peekable([])
        with pytest.raises(StopIteration):
            peekable.peek(custom_marker)

    def test_peek_with_non_iterable(self):
        with pytest.raises(TypeError):
            self.Peekable(None)

    def test_peek_with_empty_iterable(self):
        peekable = self.Peekable([])
        assert peekable.peek(default='default_value') == 'default_value'

